+      ;;
+    show)
+      echo "{\"id\":\"` + beadID + `\",\"title\":\"Show\"}"
+      exit 0
+      ;;
+  esac
+done
+for arg in "$@"; do
+  if [ "$arg" = "update" ]; then
+    echo "Updated"
+    exit 0
+  fi
+done
+echo "OK"
+`
+	if err := os.WriteFile(path, []byte(script), 0755); err != nil {
+		t.Fatalf("write stub br: %v", err)
